const INTERNATIONAL_DATA = [{"id":"11_the_united_nations_system","name":"1.1  The United Nations System","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"","optional":"","core_purpose":""},{"id":"unga_united_nations_general_assembly","name":"UNGA — United Nations General Assembly","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (International Institutions), GS2 (India's Foreign Policy)","optional":"Political Science & IR (Paper 2) — democratic legitimacy of global governance","core_purpose":"The only universal deliberative body where each state has one vote regardless of size. Its resolutions are non-binding but carry enormous norm-setting weight. It serves as the world's moral megaphone — pressure on UNSC permanent members, creation of new international law through declarations, and election of non-permanent UNSC members. India's consistent election reflects its soft-power standing."},{"id":"unsc_united_nations_security_council","name":"UNSC — United Nations Security Council","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — global governance), GS2 (India as emerging power)","optional":"Political Science & IR (Paper 2) — reform debates, veto power, P5 dynamics","core_purpose":"The only UN body whose decisions are legally binding on all member states under Chapter VII. The P5 veto is simultaneously the source of its authority (great powers must comply) and its paralysis (great powers can shield clients). India's bid for permanent membership is the single most important reform question in UPSC IR. The UNSC's intellectual tension: effectiveness vs. representativeness."},{"id":"icj_international_court_of_justice","name":"ICJ — International Court of Justice","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR, International Law)","optional":"Law (International Law paper) — jurisdiction, contentious cases, advisory opinions","core_purpose":"The principal judicial organ of the UN. Adjudicates interstate disputes (contentious jurisdiction requires state consent) and gives advisory opinions on legal questions from UN organs. Enforces no judgment — relies on UNSC for compliance. Intellectual core: whether international law can be genuine law without a sovereign enforcer."},{"id":"unhrc_un_human_rights_council","name":"UNHRC — UN Human Rights Council","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR, human rights), GS1 (social issues — linkage)","optional":"Political Science & IR, Sociology (human rights discourse), Law","core_purpose":"Replaced the discredited Commission on Human Rights in 2006. Conducts Universal Periodic Reviews (UPR) of all member states' human rights records. The core tension: countries with poor human rights records routinely win elections to the Council, exposing the gap between the body's normative mandate and its political composition. India engages strategically — co-authoring resolutions while deflecting scrutiny on Kashmir."},{"id":"who_world_health_organisation","name":"WHO — World Health Organisation","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (health governance, international bodies), GS3 (COVID-19 policy linkages)","optional":"Public Administration (health policy), Medical Sciences","core_purpose":"Coordinates international public health responses, sets health standards, and manages the International Health Regulations (IHR). Its structural flaw — voluntary, assessed contributions dominated by a few donors — gives rich states disproportionate agenda-setting power. Post-COVID, WHO reform (financing, transparency, early warning) is a live UPSC issue."},{"id":"fao_food_and_agriculture_organisation","name":"FAO — Food and Agriculture Organisation","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS3 (food security, agriculture), GS2 (international bodies)","optional":"Agriculture, Geography","core_purpose":"Collects global agricultural data, sets food safety standards (Codex Alimentarius with WHO), and coordinates food security responses. The SOFA (State of Food and Agriculture) and SOFI (State of Food Security and Nutrition) reports are primary UPSC source material. Intellectual purpose: translating agrarian complexity into international policy coordination."},{"id":"unesco_un_educational_scientific_and_cultural_organisation","name":"UNESCO — UN Educational, Scientific and Cultural Organisation","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS1 (culture, heritage), GS2 (IR)","optional":"History (World Heritage linkages), Public Administration","core_purpose":"Manages the World Heritage Sites list, drives global literacy and press freedom agendas, and governs the international scientific commons. Intellectual core: soft power through culture. India has 42 World Heritage Sites — a recurring factual anchor in UPSC. US withdrawal (2018) and rejoining (2023) reflects UNESCO's politicisation."},{"id":"unep_un_environment_programme","name":"UNEP — UN Environment Programme","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS3 (environment, climate change)","optional":"Geography, Public Administration","core_purpose":"The principal UN body for the global environment — sets norms, monitors environmental indicators (Emissions Gap Report, Adaptation Gap Report), and provides secretariat functions for major environmental treaties (Basel, Rotterdam, Stockholm Conventions). Intellectual function: translating ecological science into political obligation."},{"id":"wfp_world_food_programme","name":"WFP — World Food Programme","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS3 (food security), GS2 (international bodies)","optional":"Geography, Agriculture","core_purpose":"The world's largest humanitarian organisation — delivers food in conflict and disaster zones. Won the 2020 Nobel Peace Prize. Distinguished from FAO by operational (not normative) function. UPSC tests understanding of food security architecture — WFP handles emergencies; FAO handles structural food systems."},{"id":"unicef_un_childrens_fund","name":"UNICEF — UN Children's Fund","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (social development, international bodies)","optional":"Sociology, Public Administration","core_purpose":"Focuses on child survival, development and protection. Its annual State of the World's Children report is a primary data source. Intellectual function: child rights as a subset of human rights, with the Convention on the Rights of the Child as the legal backbone."},{"id":"ilo_international_labour_organisation","name":"ILO — International Labour Organisation","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (labour rights, social justice), GS3 (economic development — labour)","optional":"Political Science & IR, Public Administration, Sociology","core_purpose":"The only tripartite UN agency — governments, employers, and workers all participate. Sets international labour standards (ILO Conventions) that feed directly into national labour law. India has ratified relatively few core conventions — a recurring point of UPSC analysis. Intellectual core: can global labour standards survive the race to the bottom in global supply chains?"},{"id":"12_bretton_woods_institutions","name":"1.2  Bretton Woods Institutions","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"","optional":"","core_purpose":""},{"id":"imf_international_monetary_fund","name":"IMF — International Monetary Fund","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (international bodies), GS3 (Indian economy — BoP, exchange rate)","optional":"Economics (Paper 1 — money, BoP), Public Administration","core_purpose":"Lender of last resort for countries facing balance-of-payments crises. Provides conditional lending (structural adjustment) in exchange for macroeconomic policy changes. IMF conditionality is one of the most contested concepts in development economics — does it impose austerity on the poor to protect creditors? Voting shares are GDP-weighted, giving the US an effective veto. India's SDR quota, IMF surveillance reports (Article IV consultations) — key UPSC anchors."},{"id":"world_bank_group","name":"World Bank Group","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (international bodies), GS3 (development financing, infrastructure)","optional":"Economics, Public Administration","core_purpose":"Long-term development lending, not crisis management. The Bank Group includes IBRD (middle-income countries), IDA (poorest countries), IFC (private sector), MIGA (investment guarantees). World Bank's Ease of Doing Business Index (discontinued 2021 amid data manipulation scandal) shaped India's reform agenda for years. Intellectual purpose: whether external capital can catalyse development or whether it creates debt dependency."},{"id":"wto_world_trade_organisation","name":"WTO — World Trade Organisation","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — trade), GS3 (Indian economy — trade policy, agriculture)","optional":"Economics (international trade), Law (international trade law), Political Science & IR","core_purpose":"Rules-based multilateral trading system — administers trade agreements, resolves disputes through the Dispute Settlement Body (DSB), and negotiates new trade rules (Doha Round, now stalled). India's key WTO positions: food security exemptions for public stockholding (Bali/Nairobi decisions), agricultural subsidies, TRIPS flexibilities for generic medicines. Intellectual core: free trade as ideology vs. development tool."},{"id":"13_regional_bodies","name":"1.3  Regional Bodies","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"","optional":"","core_purpose":""},{"id":"saarc_south_asian_association_for_regional_cooperation","name":"SAARC — South Asian Association for Regional Cooperation","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (India's Neighbourhood Policy, regional cooperation)","optional":"Political Science & IR, Geography","core_purpose":"Founded 1985 as a platform for South Asian economic integration. Has been effectively paralysed by India-Pakistan tensions — SAARC summits suspended since 2016. Intellectual function: exposes the limits of functionalist integration theory when bilateral political conflicts override multilateral economic logic. India's pivot to BIMSTEC as an alternative is a key strategic shift to understand."},{"id":"asean_association_of_southeast_asian_nations","name":"ASEAN — Association of Southeast Asian Nations","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (India's Act East Policy, regional bodies)","optional":"Political Science & IR, Geography","core_purpose":"The most successful regional integration project in the developing world. Built on the ASEAN Way — consensus, non-interference, incremental cooperation. India's Act East Policy is anchored on ASEAN centrality. ASEAN+6 architecture (with India, China, Japan, South Korea, Australia, NZ) shapes regional trade geography. Intellectual core: whether the ASEAN Way is genuine pluralism or a shield for authoritarian regimes."},{"id":"sco_shanghai_cooperation_organisation","name":"SCO — Shanghai Cooperation Organisation","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — India's strategic partnerships, Russia-China axis), GS3 (security)","optional":"Political Science & IR, Geography","core_purpose":"Started as a border management mechanism among post-Soviet Central Asian states and China; expanded into a broad security-economic bloc. India and Pakistan joined in 2017. SCO's intellectual significance for India: engaging with a China-Russia-dominated forum without compromising strategic autonomy. The Rustam Nazarov provision allows members to discuss terrorism — a key India interest vs. Pakistan."},{"id":"brics_brazil_russia_india_china_south_africa","name":"BRICS — Brazil, Russia, India, China, South Africa","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — India's multilateral engagements, emerging economies), GS3 (NDB)","optional":"Political Science & IR, Economics","core_purpose":"Not a formal institution but a strategic forum challenging Western-dominated multilateral order. Created the New Development Bank (NDB) and Contingent Reserve Arrangement (CRA) as alternatives to World Bank and IMF. BRICS expansion (2024 — Egypt, Ethiopia, Iran, UAE, Saudi Arabia) is a pivotal development. Intellectual core: can the Global South build parallel institutions or does it inevitably replicate existing power asymmetries?"},{"id":"g20_group_of_twenty","name":"G20 — Group of Twenty","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (global governance, economic diplomacy), GS3 (global economy)","optional":"Economics, Political Science & IR, Public Administration","core_purpose":"The premier forum for international economic cooperation — represents 85% of global GDP. India's G20 Presidency (2023) was a landmark: New Delhi Declaration, African Union admission, Digital Public Infrastructure agenda. Intellectual function: G20 as informal governance filling the gap where formal multilateral institutions (WTO, IMF) are deadlocked. No binding decisions — influence through political will and communiqués."},{"id":"g7_group_of_seven","name":"G7 — Group of Seven","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (global governance, India's engagement with developed world)","optional":"Political Science & IR, Economics","core_purpose":"Club of advanced industrial democracies (US, UK, France, Germany, Italy, Canada, Japan + EU). Sets the normative agenda for the liberal international order — sanctions regimes, climate finance pledges, technology governance. India is invited as an outreach partner, not a member — signals both recognition of India's weight and the G7's residual developed-country exclusivity."},{"id":"eu_european_union","name":"EU — European Union","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (regional integration models, comparative politics)","optional":"Political Science & IR (integration theory), Economics","core_purpose":"The most ambitious experiment in post-sovereign regional governance — common market, currency (Eurozone), free movement (Schengen), common trade policy. For UPSC, the EU is a comparative model: what does deep integration require (pooled sovereignty) and where does it break down (Brexit, Eurozone debt crises, democratic deficit)? India-EU FTA negotiations are a live issue."},{"id":"au_african_union","name":"AU — African Union","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — India-Africa relations, South-South cooperation)","optional":"Political Science & IR, Geography","core_purpose":"Successor to OAU; 55-member pan-African body with an ambitious agenda (Agenda 2063, African Continental Free Trade Area — AfCFTA). India-Africa relations — Forum for India-Africa Summit (FIAS), technology transfers, developmental cooperation — are a recurring UPSC theme. AU's G20 membership (gained at India's G20 Presidency 2023) is a landmark."},{"id":"quad_quadrilateral_security_dialogue","name":"QUAD — Quadrilateral Security Dialogue","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — Indo-Pacific, security architecture), GS3 (security)","optional":"Political Science & IR","core_purpose":"India, US, Australia, Japan. Not a formal military alliance but a strategic framework aimed at a free and open Indo-Pacific — implicitly a counterweight to Chinese assertiveness. QUAD's intellectual tension for India: how to participate in a US-led security architecture while maintaining strategic autonomy (no formal mutual-defence treaty). Focus areas: vaccines (QUAD Vaccine Partnership), climate, critical and emerging technologies, maritime security."},{"id":"bimstec_bay_of_bengal_initiative_for_multisectoral_technical","name":"BIMSTEC — Bay of Bengal Initiative for Multi-Sectoral Technical and Economic Cooperation","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (India's Neighbourhood First / Act East, regional cooperation)","optional":"Political Science & IR, Geography","core_purpose":"Links South and Southeast Asia around the Bay of Bengal — India, Bangladesh, Sri Lanka, Myanmar, Thailand, Bhutan, Nepal. For India, BIMSTEC is increasingly preferred over SAARC because it excludes Pakistan and includes ASEAN gateway states. Its intellectual significance: India using geography creatively to build sub-regional integration that sidesteps the Pakistan problem."},{"id":"14_climate_governance_architecture","name":"1.4  Climate Governance Architecture","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"","optional":"","core_purpose":""},{"id":"ipcc_intergovernmental_panel_on_climate_change","name":"IPCC — Intergovernmental Panel on Climate Change","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS3 (environment — climate change science and policy)","optional":"Geography","core_purpose":"Does not conduct original research — synthesises the global scientific literature into Assessment Reports (ARs) used by policymakers. The Summary for Policymakers (SPM) is negotiated line by line between governments and scientists. Intellectual significance: the IPCC process is the most rigorous example of science-policy interface in global governance. Its AR6 (2022) established 1.5°C as the critical threshold and declared 'unequivocal' human causation."},{"id":"unfccc_un_framework_convention_on_climate_change","name":"UNFCCC — UN Framework Convention on Climate Change","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS3 (environment — climate negotiation architecture)","optional":"Geography, Political Science & IR","core_purpose":"The 1992 framework treaty establishing the principle of Common But Differentiated Responsibilities (CBDR) — developed countries must act first and support developing countries. All subsequent climate agreements (Kyoto, Paris) are made under the UNFCCC umbrella. The Conference of Parties (COP) is the supreme decision-making body — COP21 (Paris), COP26 (Glasgow), COP28 (Dubai) are key milestones."},{"id":"paris_agreement_architecture","name":"Paris Agreement Architecture","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS3 (climate change policy — India's commitments, NDCs)","optional":"Geography, Political Science & IR, Law","core_purpose":"The 2015 Paris Agreement (in force 2016) represents a paradigm shift from Kyoto's top-down binding targets to a bottom-up system of Nationally Determined Contributions (NDCs). Each country sets its own targets. The ratchet mechanism requires progressively ambitious NDCs every five years. Key concepts: 1.5°C goal, net zero, Loss and Damage (operationalised at COP27), climate finance ($100bn/year pledge). India's NDC commitments (500 GW renewables by 2030, net zero by 2070) are core UPSC content."},{"id":"15_nuclear_governance_architecture","name":"1.5  Nuclear Governance Architecture","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"","optional":"","core_purpose":""},{"id":"iaea_international_atomic_energy_agency","name":"IAEA — International Atomic Energy Agency","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS3 (nuclear security), GS2 (IR — India-IAEA relations)","optional":"Political Science & IR","core_purpose":"Dual mandate: promote peaceful uses of nuclear energy AND verify that nuclear materials are not diverted to weapons (safeguards). India's Additional Protocol with IAEA (post-2008 NSG waiver) governs civilian nuclear programme inspections. Intellectual tension: IAEA must simultaneously serve as nuclear promoter and nuclear watchdog."},{"id":"npt_nuclear_nonproliferation_treaty","name":"NPT — Nuclear Non-Proliferation Treaty","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — nuclear policy), GS3 (internal/external security)","optional":"Political Science & IR, Law","core_purpose":"The foundational nuclear governance instrument (1968) — divides the world into nuclear weapon states (NWS: P5) and non-nuclear weapon states (NNWS). Three pillars: non-proliferation, disarmament, peaceful use. India, Pakistan, Israel — non-signatories. North Korea withdrew. The NPT's intellectual crisis: NWS have not disarmed (Article VI obligation), yet demand non-proliferation from everyone else. India's position: discriminatory and permanent inequality is unjust."},{"id":"ctbt_comprehensive_nucleartestban_treaty","name":"CTBT — Comprehensive Nuclear-Test-Ban Treaty","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — India's nuclear doctrine), GS3 (security)","optional":"Political Science & IR","core_purpose":"Bans all nuclear test explosions. Signed 1996, not yet in force because eight Annex 2 states (including India, Pakistan, US, China) have not ratified. India refuses to sign: sees CTBT as a non-proliferation tool that freezes the existing technological gap without requiring NWS disarmament. India's 1998 Pokhran II tests were conducted before CTBT entered into force negotiations concluded."},{"id":"nsg_nuclear_suppliers_group","name":"NSG — Nuclear Suppliers Group","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — India's nuclear deal), GS3 (security)","optional":"Political Science & IR","core_purpose":"An informal cartel of 48 states that controls the export of nuclear materials and technology. The 2008 NSG waiver for India — despite India being a non-NPT state — was a landmark US-India achievement (the 123 Agreement / Civil Nuclear Deal). India's bid for full NSG membership is contested, principally by China, which insists on NPT membership as a precondition. Intellectual core: can non-treaty states be trusted with nuclear trade?"},{"id":"16_trade_architecture_beyond_wto","name":"1.6  Trade Architecture Beyond WTO","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"","optional":"","core_purpose":""},{"id":"rcep_regional_comprehensive_economic_partnership","name":"RCEP — Regional Comprehensive Economic Partnership","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — trade diplomacy), GS3 (Indian economy — trade)","optional":"Economics, Political Science & IR","core_purpose":"The world's largest trade bloc by GDP and population — ASEAN + China, Japan, South Korea, Australia, New Zealand. India negotiated RCEP for seven years then walked out in 2019, citing inadequate protection for farmers and manufacturers against Chinese import surges. India's non-membership is one of the most debated trade policy decisions in recent years — strategic protection or self-defeating isolation?"},{"id":"bilateral_ftas_indias_framework","name":"Bilateral FTAs — India's Framework","type":"PART 1 — INTERNATIONAL ORGANISATIONS","gs_papers":"GS Paper(s):  GS2 (IR — trade diplomacy), GS3 (trade policy)","optional":"Economics, Political Science & IR","core_purpose":"India has pursued bilateral FTAs where WTO Doha and regional mega-deals stall. Key agreements: India-UAE CEPA (2022), India-Australia ECTA (2022), India-UK FTA (under negotiation). Intellectual tension: bilateral FTAs may create trade diversion (preferential access to FTA partner at the expense of global efficiency) but provide political deliverables. UPSC tests India's selectivity in trade agreements."},{"id":"21_human_rights_treaties","name":"2.1  Human Rights Treaties","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"","optional":"","core_purpose":""},{"id":"udhr_universal_declaration_of_human_rights_1948","name":"UDHR — Universal Declaration of Human Rights (1948)","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS2 (fundamental rights — comparative, human rights)","optional":"Law (International Law), Philosophy (political philosophy), Political Science & IR","core_purpose":"Not a binding treaty but a declaration — yet it has achieved quasi-customary international law status. Basis for all subsequent human rights treaties. Eleanor Roosevelt shepherded its drafting; Hansa Mehta (India) ensured 'all human beings' replaced 'all men'. Intellectual core: universal human rights vs. cultural relativism — still the defining debate in human rights philosophy."},{"id":"iccpr_international_covenant_on_civil_and_political_rights_1","name":"ICCPR — International Covenant on Civil and Political Rights (1966)","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS2 (fundamental rights, civil liberties, constitutional law)","optional":"Law, Political Science & IR, Philosophy","core_purpose":"Converts UDHR civil-political rights into treaty obligations — right to life, fair trial, free expression, political participation. India ratified 1979. The Human Rights Committee monitors compliance. Intellectual significance for India: ICCPR rights map onto Part III of the Constitution (Articles 12–35) but India's reservations limit direct enforceability."},{"id":"icescr_international_covenant_on_economic_social_and_cultura","name":"ICESCR — International Covenant on Economic, Social and Cultural Rights (1966)","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS2 (DPSP, social rights), GS3 (development — welfare, labour)","optional":"Law, Sociology, Political Science & IR","core_purpose":"Makes economic and social rights (food, health, education, labour rights) treaty obligations — but subject to 'progressive realisation' rather than immediate enforcement. India ratified 1979. Maps onto Part IV (DPSP) of the Constitution. Intellectual core: are socio-economic rights genuine rights or political aspirations? The debate between generation theory (civil-political vs. socio-economic rights) is key to UPSC Philosophy optional."},{"id":"cedaw_convention_on_the_elimination_of_all_forms_of_discrimi","name":"CEDAW — Convention on the Elimination of All Forms of Discrimination Against Women (1979)","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS1 (women's issues), GS2 (human rights, social justice)","optional":"Law, Sociology (gender), Political Science & IR","core_purpose":"The women's bill of rights. India ratified 1993 with reservations on Articles 5(a) and 16(1) relating to personal law — reflecting tension between international norms and religious personal law systems (Muslim personal law, Hindu Succession Act). The CEDAW Committee's periodic reviews of India regularly flag the Uniform Civil Code absence, triple talaq, and marital rape law."},{"id":"crc_convention_on_the_rights_of_the_child_1989","name":"CRC — Convention on the Rights of the Child (1989)","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS2 (child rights, social justice), GS1 (social issues)","optional":"Law, Sociology, Public Administration","core_purpose":"Most widely ratified human rights treaty. Four core principles: non-discrimination, best interests of the child, right to life and development, child participation. India ratified 1992. POSCO Act, Child Labour laws, RTE Act, JJ Act are domestic implementations. Intellectual significance: first treaty to give children independent rights rather than treating them as parental property."},{"id":"22_environmental_treaties","name":"2.2  Environmental Treaties","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"","optional":"","core_purpose":""},{"id":"cbd_convention_on_biological_diversity_1992","name":"CBD — Convention on Biological Diversity (1992)","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS3 (environment — biodiversity)","optional":"Geography, Agriculture","core_purpose":"Three objectives: conservation of biodiversity, sustainable use of its components, and equitable sharing of benefits from genetic resources (Access and Benefit Sharing — ABS). The Nagoya Protocol (2010) operationalised ABS. The Kunming-Montreal Global Biodiversity Framework (2022) sets the 30x30 target — protect 30% of land and ocean by 2030. India as a megadiverse country has high stakes in biodiversity governance."},{"id":"ramsar_convention_convention_on_wetlands_1971","name":"Ramsar Convention — Convention on Wetlands (1971)","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS3 (environment — wetlands, conservation)","optional":"Geography","core_purpose":"The first modern intergovernmental treaty on ecosystem conservation — focuses on wetlands 'of international importance'. Ramsar Sites designation is a UPSC factual anchor. India has 75+ Ramsar sites as of 2023. Intellectual function: pioneer in ecosystem-services thinking — wetlands as flood buffers, water purifiers, and biodiversity hubs before this language became mainstream."},{"id":"cites_convention_on_international_trade_in_endangered_specie","name":"CITES — Convention on International Trade in Endangered Species (1973)","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS3 (environment — biodiversity, wildlife trade)","optional":"Geography","core_purpose":"Regulates international wildlife trade through a three-tier appendix system (Appendix I — complete ban; Appendix II — regulated; Appendix III — country-specific). India's tiger, elephant, leopard trade disputes appear in UPSC current affairs regularly. Intellectual core: can market mechanisms (regulated trade) conserve species better than outright bans?"},{"id":"montreal_protocol_1987","name":"Montreal Protocol (1987)","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS3 (environment — ozone, climate linkage)","optional":"Geography, Chemistry (optional linkage)","core_purpose":"The most successful environmental treaty — phased out 99% of ozone-depleting substances (CFCs, HCFCs). The Kigali Amendment (2016) extended it to phase down HFCs (greenhouse gases used as CFC substitutes). Intellectual significance: first international treaty to achieve near-universal ratification and demonstrable environmental recovery — the ozone layer is healing. Model for what climate governance could look like if it were truly binding."},{"id":"basel_rotterdam_and_stockholm_conventions","name":"Basel, Rotterdam and Stockholm Conventions","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS3 (environment — hazardous waste, chemicals)","optional":"Geography","core_purpose":"The chemical conventions cluster: Basel (1989) controls transboundary movement of hazardous wastes — prevents rich countries dumping toxics in poor ones; Rotterdam (1998) requires prior informed consent for hazardous chemical trade; Stockholm (2001) bans persistent organic pollutants (POPs). Collectively, they constitute the global chemicals governance architecture. India's e-waste challenge connects directly to Basel."},{"id":"23_economic_frameworks","name":"2.3  Economic Frameworks","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"","optional":"","core_purpose":""},{"id":"sdgs_sustainable_development_goals_agenda_2030","name":"SDGs — Sustainable Development Goals / Agenda 2030","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS2 (social development, governance), GS3 (economy, environment)","optional":"Economics, Public Administration, Sociology","core_purpose":"17 goals, 169 targets, 231 unique indicators adopted in 2015 as successor to MDGs. SDGs are universal (apply to all countries, not just developing) and integrated (poverty, health, climate, inequality are inseparable). India's VNR (Voluntary National Reviews) before the High-Level Political Forum map domestic schemes to SDG targets. Intellectual core: SDGs as a governance framework — how do aspirational targets translate into budget allocations and policy priorities without binding enforcement?"},{"id":"24_security_and_arms_control_frameworks","name":"2.4  Security and Arms Control Frameworks","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"","optional":"","core_purpose":""},{"id":"wassenaar_arrangement","name":"Wassenaar Arrangement","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS2 (IR — technology controls, India's strategic interests), GS3 (security)","optional":"Political Science & IR","core_purpose":"A multilateral export control regime for conventional weapons and dual-use goods and technologies (41 member states). India joined in 2017 — alongside membership in the Australia Group (chemical/bio weapons) and MTCR (missile technology). These memberships are a pathway to NSG membership and signal India's acceptance of non-proliferation norms while remaining outside the NPT."},{"id":"mtcr_missile_technology_control_regime","name":"MTCR — Missile Technology Control Regime","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS2 (IR), GS3 (defence/security technology)","optional":"Political Science & IR","core_purpose":"Informal political commitment (not a treaty) among 35 states to restrict export of rockets capable of delivering WMDs. India joined 2016. Membership enables procurement of advanced drone technology and legitimises India's missile programme internationally. Pakistan's repeated rejection for membership (China blocks) is a recurring asymmetry in South Asian strategic balance."},{"id":"australia_group","name":"Australia Group","type":"PART 2 — MAJOR INTERNATIONAL TREATIES AND FRAMEWORKS","gs_papers":"GS Paper(s):  GS2 (IR), GS3 (CBRN threats, internal security)","optional":"Political Science & IR","core_purpose":"Controls export of biological and chemical weapons precursors. India joined 2018. Part of India's integration into the Western-led non-proliferation architecture — a strategic dividend of the 2008 Civil Nuclear Deal framework. Intellectual function: export control regimes as non-treaty governance — effectiveness depends entirely on voluntary compliance."},{"id":"31_panchsheel_five_principles_of_peaceful_coexistence","name":"3.1  Panchsheel — Five Principles of Peaceful Coexistence","type":"PART 3 — INDIA'S FOREIGN POLICY DOCTRINE","gs_papers":"GS Paper(s):  GS2 (India's foreign policy — principles and evolution)","optional":"Political Science & IR (Paper 2 — India's foreign policy), History (modern India)","core_purpose":""},{"id":"32_nam_nonaligned_movement","name":"3.2  NAM — Non-Aligned Movement","type":"PART 3 — INDIA'S FOREIGN POLICY DOCTRINE","gs_papers":"GS Paper(s):  GS2 (India's foreign policy), GS1 (post-independence consolidation)","optional":"Political Science & IR, History (modern India)","core_purpose":""},{"id":"33_neighbourhood_first_policy","name":"3.3  Neighbourhood First Policy","type":"PART 3 — INDIA'S FOREIGN POLICY DOCTRINE","gs_papers":"GS Paper(s):  GS2 (India's foreign policy — regional relations, SAARC, BIMSTEC)","optional":"Political Science & IR","core_purpose":""},{"id":"34_act_east_policy","name":"3.4  Act East Policy","type":"PART 3 — INDIA'S FOREIGN POLICY DOCTRINE","gs_papers":"GS Paper(s):  GS2 (India's foreign policy — ASEAN, Indo-Pacific, Act East)","optional":"Political Science & IR, Geography","core_purpose":""},{"id":"35_indopacific_indias_strategic_doctrine","name":"3.5  Indo-Pacific — India's Strategic Doctrine","type":"PART 3 — INDIA'S FOREIGN POLICY DOCTRINE","gs_papers":"GS Paper(s):  GS2 (IR — strategic affairs, Indo-Pacific), GS3 (maritime security)","optional":"Political Science & IR, Geography","core_purpose":""},{"id":"36_strategic_autonomy_the_overarching_doctrine","name":"3.6  Strategic Autonomy — The Overarching Doctrine","type":"PART 3 — INDIA'S FOREIGN POLICY DOCTRINE","gs_papers":"GS Paper(s):  GS2 (India's foreign policy — principles)","optional":"Political Science & IR","core_purpose":""}];
